import { compact } from 'lodash-es';

/**
 * A threshold range
 * @public
 */
export interface ColoredRange {
  /** Range starting point */
  from: number;
  /** Range ending point */
  to: number;
  /** The color to use in this range  */
  color?: string;
}

/**
 * @internal
 */
export function isColoredRangeArray(
  colorRange: unknown,
): colorRange is ColoredRange[] {
  return (
    Array.isArray(colorRange) &&
    compact(colorRange).length > 0 &&
    Object.keys(colorRange[0]).includes('to') &&
    Object.keys(colorRange[0]).includes('from')
  );
}
